export const getCountryQuestions = (countryCode: string): Question[] => {
  const country = countryHistoryData.find(c => c.countryCode === countryCode);
  return country?.questions || [];
};

export const getCountryQuestionsByLevel = (countryCode: string, level: number): Question[] => {
  const questions = getCountryQuestions(countryCode);
  let difficulty: 'easy' | 'medium' | 'hard';
  if (level <= 10) difficulty = 'easy';
  else if (level <= 20) difficulty = 'medium';
  else difficulty = 'hard';
  
  return questions.filter(q => q.difficulty === difficulty);
};

// Get all country history questions by level (for generic play)
export const getAllCountryQuestionsByLevel = (level: number): Question[] => {
  // Combine all country questions and generic ones
  const allQuestions = countryHistoryData.flatMap(c => c.questions);
  const combinedQuestions = [...allQuestions, ...genericCountryQuestions];
  
  // Get all easy questions for levels 1-10 (all easy mode)
  const easyQuestions = combinedQuestions.filter(q => q.difficulty === 'easy');
  
  if (level <= 10) {
    // Levels 1-10: All easy mode, different questions for each level
    const startIndex = (level - 1) * 10;
    const endIndex = startIndex + 10;
    
    if (endIndex <= easyQuestions.length) {
      return easyQuestions.slice(startIndex, endIndex);
    } else {
      // Cycle through available questions
      const questions: Question[] = [];
      for (let i = 0; i < 10; i++) {
        questions.push(easyQuestions[(startIndex + i) % easyQuestions.length]);
      }
      return questions;
    }
  }
  
  // Levels 11+: Use difficulty-based filtering
  let difficulty: 'easy' | 'medium' | 'hard';
  if (level <= 20) difficulty = 'medium';
  else difficulty = 'hard';
  
  const filteredQuestions = combinedQuestions.filter(q => q.difficulty === difficulty);
  const startIndex = ((level - 1) % Math.ceil(filteredQuestions.length / 10)) * 10;
  const endIndex = Math.min(startIndex + 10, filteredQuestions.length);
  
  if (endIndex <= filteredQuestions.length) {
    return filteredQuestions.slice(startIndex, endIndex);
  } else {
    const questions: Question[] = [];
    for (let i = 0; i < 10; i++) {
      questions.push(filteredQuestions[(startIndex + i) % filteredQuestions.length]);
    }
    return questions;
  }
};

